function trap(height) {
  let total = 0;
  for (let i = 0; i < height.length; i++) {
    let maxLeft = 0;
    let maxRight = 0;

    for (let l = 0; l <= i; l++) maxLeft = Math.max(maxLeft, height[l]);
    for (let r = i; r < height.length; r++) maxRight = Math.max(maxRight, height[r]);

    const water = Math.min(maxLeft, maxRight) - height[i];
    if (water > 0) total += water;
  }
  return total;
}

int Trap(int[] height)
{
    int n = height.Length;
    int water = 0;

    for (int i = 1; i < n - 1; i++)
    {
        int leftMax = 0, rightMax = 0;
        for (int l = 0; l <= i; l++) leftMax = Math.Max(leftMax, height[l]);
        for (int r = i; r < n; r++) rightMax = Math.Max(rightMax, height[r]);

        water += Math.Min(leftMax, rightMax) - height[i];
    }

    return water;
}

function trap(height) {
  let left = 0;
  let right = height.length - 1;
  let leftMax = 0;
  let rightMax = 0;
  let total = 0;

  while (left < right) {
    if (height[left] <= height[right]) {
      if (height[left] >= leftMax) leftMax = height[left];
      else total += leftMax - height[left];
      left++;
    } else {
      if (height[right] >= rightMax) rightMax = height[right];
      else total += rightMax - height[right];
      right--;
    }
  }

  return total;
}

